import{bV as o,aL as n,u as s,G as a}from"./chunks/framework.6JFQ6gON.js";const g=JSON.parse('{"title":"Python简介","description":"","frontmatter":{"date":"2026-04-08T09:13:44.000Z","title":"Python简介","categories":["人工智能技术","Python"],"tags":["编程语言","Python"]},"headers":[],"relativePath":"02.人工智能技术/01.Python/01.Python简介.md","filePath":"02.人工智能技术/01.Python/01.Python简介.md"}'),r={name:"02.人工智能技术/01.Python/01.Python简介.md"};function e(h,t,i,p,l,d){return n(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="python简介" tabindex="-1">Python简介 <a class="header-anchor" href="#python简介" aria-label="Permalink to &quot;Python简介&quot;">​</a></h1><h3 id="python发展历史" tabindex="-1">Python发展历史 <a class="header-anchor" href="#python发展历史" aria-label="Permalink to &quot;Python发展历史&quot;">​</a></h3><h4 id="缘起-一个圣诞假期的-私活-项目" tabindex="-1">缘起：一个圣诞假期的“私活”项目 <a class="header-anchor" href="#缘起-一个圣诞假期的-私活-项目" aria-label="Permalink to &quot;缘起：一个圣诞假期的“私活”项目&quot;">​</a></h4><p>Python 的故事始于 1989 年的圣诞节。当时，荷兰程序员 <strong>Guido van Rossum</strong> 正在阿姆斯特丹的家中休假。为了打发无聊的假期时光，他决定启动一个个人项目：设计一门新的脚本解释语言。</p><hr><h4 id="初衷-继承-abc-语言-填补-c-与-shell-的空白" tabindex="-1">初衷：继承 ABC 语言，填补 C 与 Shell 的空白 <a class="header-anchor" href="#初衷-继承-abc-语言-填补-c-与-shell-的空白" aria-label="Permalink to &quot;初衷：继承 ABC 语言，填补 C 与 Shell 的空白&quot;">​</a></h4><p>Guido van Rossum 的灵感并非凭空而来，而是源于他之前参与设计的一门名为 ABC 的教学语言。他认为 ABC 语言非常优美和强大，尤其适合非专业程序员，但其致命缺陷在于非开放性和扩展性差。因此，Guido van Rossum 创造 Python 的初衷非常明确：继承 ABC 语言简洁、易读、易用的核心特性；弥补其非开放、难扩展的缺陷，打造一门能与 C 语言交互的开放语言；填补 C 语言和 Shell 脚本之间的空白，既能快速编程，又具备强大功能。</p><hr><h4 id="命名-源自喜剧团体-而非-蟒蛇" tabindex="-1">命名：源自喜剧团体，而非“蟒蛇” <a class="header-anchor" href="#命名-源自喜剧团体-而非-蟒蛇" aria-label="Permalink to &quot;命名：源自喜剧团体，而非“蟒蛇”&quot;">​</a></h4><p>这是一个有趣的误会。很多人以为 Python 这个名字来源于「蟒蛇」，但实际上，Guido van Rossum 是一位英国喜剧团体 Monty Python 的忠实粉丝。为了体现这门新语言的趣味性和不严肃的风格，他直接从自己喜爱的喜剧《蒙提·派森的飞行马戏团》（Monty Python&#39;s Flying Circus）中汲取灵感，将这门语言命名为 「Python」 。所以，Python 的 Logo 虽然是条蟒蛇，但它的名字其实源于一个喜剧团体。</p><hr><h4 id="灵魂-《python之禅》的哲学指引" tabindex="-1">灵魂：《Python之禅》的哲学指引 <a class="header-anchor" href="#灵魂-《python之禅》的哲学指引" aria-label="Permalink to &quot;灵魂：《Python之禅》的哲学指引&quot;">​</a></h4><p>Python 的灵魂，在于其独特的设计哲学——「Python之禅」（The Zen of Python）。这套哲学由 Python 核心开发者蒂姆·彼得斯（Tim Peters）于 2004 年撰写，它并非一门技术，而是 19 条指导代码编写的格言，凝聚了 Python 社区的价值观。你可以在任何 Python 环境中输入 <code>import this</code> 来一窥其全貌。</p><ul><li><strong>优美胜于丑陋（Beautiful is better than ugly.）：</strong> 代码不仅要功能正确，还要易于阅读和理解。优美的代码通常更易于维护和扩展。</li><li><strong>明确胜于隐晦（Explicit is better than implicit.）：</strong> 代码应明确表达意图，避免隐藏的逻辑或“魔法”行为，确保每段代码的行为都可追溯、可预测。</li><li><strong>简单胜于复杂（Simple is better than complex.）：</strong> 能用简单方法解决的问题，就不要引入不必要的复杂结构。</li><li><strong>可读性很重要（Readability counts.）：</strong> 这是 Python 的核心。代码是写给人看的，其次才是机器。良好的命名、注释和格式是必需的。</li></ul><p>「Python之禅」不仅适用于 Python ，也为所有软件开发提供了通用智慧，它倡导的是一种清晰、简洁、务实的编程美学。</p><hr><h4 id="发展-从-0-9-0-到-3-0-的演进之路" tabindex="-1">发展：从 0.9.0 到 3.0 的演进之路 <a class="header-anchor" href="#发展-从-0-9-0-到-3-0-的演进之路" aria-label="Permalink to &quot;发展：从 0.9.0 到 3.0 的演进之路&quot;">​</a></h4><p>1991 年，Guido van Rossum 发布了 Python 的第一个公开发行版（0.9.0）。这个版本已经包含了类、函数、异常处理等核心特性，奠定了 Python 的基础。</p><ul><li><strong>1994 年：</strong> Python 1.0 版本发布，引入了函数式编程工具（如 lambda、map、filter），标志着语言走向成熟。</li><li><strong>2000 年：</strong> Python 2.0 发布，增加了垃圾回收机制和对 Unicode 的支持，生态开始蓬勃发展。</li><li><strong>2008 年：</strong> Python 3.0 发布，这是一次不向后兼容的重大升级，旨在解决 Python 2.x 中的设计缺陷，为 Python 的未来发展铺平了道路。</li></ul><p>从 Guido van Rossum 的个人项目到如今的全球主流编程语言，Python 的成功源于其简洁的设计哲学、强大的社区支持和在 Web 开发、数据分析、人工智能等领域的广泛应用。</p><h3 id="python-代码执行过程" tabindex="-1">Python 代码执行过程： <a class="header-anchor" href="#python-代码执行过程" aria-label="Permalink to &quot;Python 代码执行过程：&quot;">​</a></h3><p>当你满怀期待地敲下 <code>python my_script.py</code>，然后按下回车键，屏幕上最终呈现出你期望的结果。这看似简单的瞬间，背后却上演着一场由 Python 解释器精心编排的复杂“魔术”。今天，就让我们一同揭开这层神秘的面纱，深入探索 Python 代码从文本到执行的完整旅程，并看看它与其他语言有何不同。</p><hr><h4 id="第一步-编译-是的-你没听错" tabindex="-1">第一步：编译？是的，你没听错！ <a class="header-anchor" href="#第一步-编译-是的-你没听错" aria-label="Permalink to &quot;第一步：编译？是的，你没听错！&quot;">​</a></h4><p>很多人认为 Python 是纯粹的“解释型语言”，代码被一行行直接执行。这其实是一个常见的误解。实际上，在 Python 代码真正开始“跑”起来之前，它首先要经历一个<strong>编译</strong>阶段。</p><p>这个编译过程并非像 C/C++ 那样生成可以直接在 CPU 上运行的机器码，而是将我们编写的人类可读的源代码（<code>.py</code>文件），转换成一种名为**字节码（Bytecode）**的中间形态。</p><p>你可以把字节码想象成一种为 Python 虚拟机（PVM）量身定制的、与平台无关的低级指令集。它比源代码更接近机器，但又不依赖于任何特定的硬件或操作系统。</p><p><strong>那么，这个编译过程是如何发生的呢？</strong></p><ol><li><strong>词法分析（Tokenization）</strong>：解释器首先会像阅读文章一样，将你的源代码字符串分解成一个个有意义的“单词”，我们称之为“标记（Token）”。比如 <code>x = 10</code> 会被分解为标识符 <code>x</code>、赋值运算符 <code>=</code> 和数字常量 <code>10</code>。</li><li><strong>语法分析（Parsing）</strong>：接着，解释器会检查这些标记的排列组合是否符合 Python 的语法规则。它会构建一棵<strong>抽象语法树（Abstract Syntax Tree, AST）</strong>。AST 是代码结构的树状表示，清晰地展现了代码的逻辑层次。如果代码中存在语法错误（比如漏了冒号或括号不匹配），程序就会在这一步戛然而止，并抛出 <code>SyntaxError</code>。</li><li><strong>生成字节码</strong>：一旦 AST 构建成功，Python 的编译器就会遍历这棵树，将其翻译成一系列的字节码指令。</li></ol><p><strong>一个有趣的细节：<code>.pyc</code>文件</strong></p><p>你可能在项目目录中见过名为 <code>__pycache__</code> 的文件夹，里面存放着 <code>.pyc</code> 文件。这些就是编译后生成的字节码文件！Python 解释器会缓存它们，当下次导入同一个模块时，如果源代码没有改变，解释器就会直接加载这些 <code>.pyc</code> 文件，跳过耗时的编译步骤，从而加快程序的启动速度。</p><hr><h4 id="第二步-python-虚拟机-pvm-登场" tabindex="-1">第二步：Python 虚拟机（PVM）登场 <a class="header-anchor" href="#第二步-python-虚拟机-pvm-登场" aria-label="Permalink to &quot;第二步：Python 虚拟机（PVM）登场&quot;">​</a></h4><p>字节码生成之后，真正的主角——<strong>Python 虚拟机（Python Virtual Machine, PVM）</strong>——才正式登台。PVM 是一个用 C 语言实现的、基于栈的虚拟机。你可以把它想象成一个虚拟的、简化版的 CPU ，它的任务就是读取并执行字节码指令。</p><p>PVM 的执行过程是一个巨大的循环，它不断地从字节码中取出指令，然后根据指令的含义执行相应的操作。</p><p>* <strong>基于栈的操作</strong>：PVM 内部维护着一个“操作数栈”。大多数指令都会与这个栈交互。例如，<code>LOAD_CONST</code> 指令会将一个常量值压入栈顶，而 <code>BINARY_ADD</code> 指令则会从栈顶弹出两个值，将它们相加，再把结果压回栈中。</p><p>* <strong>逐条执行</strong>：PVM 就这样一条接一条地执行字节码，完成变量赋值、函数调用、循环控制等各种任务。当遇到函数调用时，PVM 会创建一个新的“栈帧（Frame）”来管理该函数的局部变量和执行上下文，函数执行完毕后，这个栈帧就会被销毁。</p><hr><h4 id="第三步-与操作系统握手" tabindex="-1">第三步：与操作系统握手 <a class="header-anchor" href="#第三步-与操作系统握手" aria-label="Permalink to &quot;第三步：与操作系统握手&quot;">​</a></h4><p>PVM 执行的字节码指令本身并不能直接操作硬件。当程序需要进行文件读写、网络通信或在屏幕上打印内容时，PVM 会调用底层的 C 库函数，这些 C 函数再与操作系统（如Windows、Linux、macOS）进行交互，最终由操作系统调度硬件资源来完成实际工作。</p><p>例如，当你执行 <code>print(&quot;Hello, World!&quot;)</code> 时，PVM会执行一系列字节码来准备字符串和调用 <code>print</code> 函数，最终这个调用会传递给操作系统的标准输出接口，将文本显示在你的终端上。</p><hr><h4 id="一个无法绕开的-角色-全局解释器锁-gil" tabindex="-1">一个无法绕开的“角色”：全局解释器锁（GIL） <a class="header-anchor" href="#一个无法绕开的-角色-全局解释器锁-gil" aria-label="Permalink to &quot;一个无法绕开的“角色”：全局解释器锁（GIL）&quot;">​</a></h4><p>在讨论Python执行时，有一个话题总是绕不开，那就是<strong>全局解释器锁（Global Interpreter Lock, GIL）</strong>。</p><p>GIL是CPython（最常用的Python解释器）中的一个机制，它确保在任何时刻，只有一个线程在执行Python字节码。这主要是为了简化CPython的内存管理（尤其是引用计数机制），避免多线程同时修改对象时出现数据竞争。</p><p>然而，GIL也带来了一个广为人知的“副作用”：在CPU密集型任务中，Python的多线程并不能真正利用多核CPU的优势，有时甚至可能比单线程更慢。这也是为什么在处理计算密集型任务时，我们更推荐使用多进程（<code>multiprocessing</code>）而非多线程。</p><hr><h4 id="python-vs-其他语言-一场执行模式的较量" tabindex="-1">Python vs. 其他语言：一场执行模式的较量 <a class="header-anchor" href="#python-vs-其他语言-一场执行模式的较量" aria-label="Permalink to &quot;Python vs. 其他语言：一场执行模式的较量&quot;">​</a></h4><p>为了更深刻地理解Python的执行模式，我们不妨将它与编译型语言（如C/C++）和另一种混合型语言（如Java）做个对比。</p><p><strong>Python vs. C/C++：编译型与“混合型”的碰撞</strong></p><p>* <strong>C/C++（纯编译型）</strong>：C/C++代码需要由编译器（如GCC）一次性全部翻译成特定平台的<strong>机器码</strong>，生成一个独立的可执行文件（如Windows下的<code>.exe</code>）。这个文件可以直接被CPU执行，因此速度极快。但缺点是，这个<code>.exe</code>文件无法在其他操作系统上运行，跨平台性差。这就像把一本英文书完整地翻译成了中文并印刷成册，读者（CPU）可以直接阅读，但这本书只能在特定地区发行。</p><p>* <strong>Python（混合型）</strong>：Python则采用“先编译成字节码，再解释执行”的模式。字节码是平台无关的，可以在任何安装了Python解释器的系统上运行，实现了“一次编写，到处运行”。但代价是，PVM需要逐条解释字节码，执行效率通常低于C/C++。这就像同声传译，演讲者（代码）说一句，翻译官（PVM）就立刻翻译一句给听众（CPU）听，虽然灵活，但总有一点点延迟。</p><p><strong>Python vs. Java：殊途同归的“中间路线”</strong></p><p>有趣的是，Python和Java在执行模式上非常相似，都属于“编译+解释”的混合型。</p><ol><li><strong>Java</strong>：<code>.java</code>源代码首先被编译成<code>.class</code>字节码文件，然后由Java虚拟机（JVM）加载并执行。JVM同样可以选择解释执行，或者使用JIT（即时编译器）将频繁执行的“热点代码”编译成本地机器码，以提升性能。</li><li><strong>Python</strong>：<code>.py</code>源代码被编译成<code>.pyc</code>字节码文件，然后由PVM解释执行。标准的CPython解释器主要是解释执行，但也有像PyPy这样的实现引入了JIT技术来加速。</li></ol><p>可以说，Python和Java都巧妙地选择了在开发效率（跨平台、动态性）和执行效率之间取得平衡的“中间路线”。</p><hr><h4 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h4><p>回顾一下，Python代码的执行并非一蹴而就，它经历了一场从高级到低级的转换之旅：</p><ol><li><strong>编译阶段</strong>：源代码（<code>.py</code>）经过词法分析和语法分析，生成抽象语法树（AST），再被编译成平台无关的字节码（<code>.pyc</code>）。</li><li><strong>执行阶段</strong>：Python虚拟机（PVM）读取并逐条解释执行字节码，通过基于栈的模型完成各种操作。</li><li><strong>系统交互</strong>：PVM在执行过程中，通过调用底层C库与操作系统交互，最终实现程序的各种功能。</li></ol><p>理解这个过程，不仅能帮助我们写出更高效的Python代码，也能让我们在遇到性能瓶颈或奇怪的行为时，能够从更底层的视角去思考和分析。</p><h3 id="python-到底是-强类型-还是-弱类型" tabindex="-1">Python 到底是“强类型”还是“弱类型”？ <a class="header-anchor" href="#python-到底是-强类型-还是-弱类型" aria-label="Permalink to &quot;Python 到底是“强类型”还是“弱类型”？&quot;">​</a></h3><p>在编程世界里，关于 Python 的类型系统，流传着一个巨大的误解。很多初学者（甚至是有经验的开发者）常常因为 Python 变量不需要声明类型，就顺口把它和 JavaScript 或 PHP 归为一类，认为它是“弱类型”语言。</p><p><strong>大错特错！</strong></p><p>今天，我们就来彻底厘清这个概念。Python 不仅不是弱类型，反而是<strong>强类型</strong>语言的坚定捍卫者。而它所具备的“不声明类型”的特性，准确的说法叫做<strong>动态类型</strong>。</p><p>这其中的区别，就像“自由”与“混乱”的区别一样重要。</p><hr><h4 id="内存的契约-为什么我们需要类型" tabindex="-1">内存的契约：为什么我们需要类型？ <a class="header-anchor" href="#内存的契约-为什么我们需要类型" aria-label="Permalink to &quot;内存的契约：为什么我们需要类型？&quot;">​</a></h4><p>要理解强类型，我们得先回到计算机的底层——内存。</p><p>在计算机的内存中，数据并不是随意堆放的。为了高效地存取数据，系统必须明确三件事：</p><ol><li><strong>存储地址</strong>：数据放在哪里？（由变量名决定）</li><li><strong>数据长度</strong>：数据占多少个字节？</li><li><strong>处理方式</strong>：数据该如何运算和转换？</li></ol><p>在 C 或 Java 这样的<strong>静态类型</strong>语言中，当你写下 <code>int n = 10;</code> 时，你实际上是在与编译器签订一份严格的契约：“嘿，编译器，给我预留 4 个字节的空间，并且我保证只往里面放整数。”</p><p>一旦你试图违背这份契约，比如把字符串塞进去，编译器就会在编译阶段直接报错，阻止程序运行。这种“先斩后奏”（先检查后运行）的机制，虽然繁琐，但极大地保证了程序的安全性。</p><hr><h4 id="动态类型-python-的-随性" tabindex="-1">动态类型：Python 的“随性” <a class="header-anchor" href="#动态类型-python-的-随性" aria-label="Permalink to &quot;动态类型：Python 的“随性”&quot;">​</a></h4><p>Python 选择了另一条路。在 Python 中，变量更像是一个“标签”或“引用”，而不是一个固定的盒子。</p><p>当你写下 <code>n = 10</code> 时，你并没有告诉 Python <code>n</code> 是什么类型。Python 会创建一个整数对象 <code>10</code>，然后把标签 <code>n</code> 贴在这个对象上。下一秒，如果你写 <code>n = &quot;Hello&quot;</code>，Python 会毫无怨言地把标签 <code>n</code> 撕下来，贴到字符串对象 <code>&quot;Hello&quot;</code>上。</p><p>这就是<strong>动态类型</strong>： * <strong>灵活性极高</strong>：你不需要关心内存分配的细节，代码写起来飞快。 * <strong>类型推断</strong>：类型是跟着值走的，而不是跟着变量走的。</p><p>但是，<strong>动态类型并不意味着弱类型</strong>。这是很多人最容易混淆的地方。</p><hr><h4 id="强类型-python-的-原则" tabindex="-1">强类型：Python 的“原则” <a class="header-anchor" href="#强类型-python-的-原则" aria-label="Permalink to &quot;强类型：Python 的“原则”&quot;">​</a></h4><p>那么，什么是<strong>强类型</strong>？</p><p>简单来说，强类型语言是一种“眼里揉不得沙子”的语言。它一旦确定了某个数据的类型，就绝不允许在不进行显式转换的情况下，对其进行违背类型规则的操作。</p><p><strong>让我们看一个经典的例子：</strong></p><p>在 JavaScript（弱类型语言）中，你可以这样做：</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;5&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 结果： &quot;52&quot; (JavaScript 猜测你想做字符串拼接)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> math </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;5&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 结果： 10 (JavaScript 猜测你想做数学运算)</span></span></code></pre></div><p>JavaScript 会试图“帮助”你，它会自动猜测你的意图，并在后台悄悄进行类型转换。这虽然方便，但也埋下了巨大的隐患——你不知道它什么时候会猜错。</p><p><strong>而在 Python（强类型语言）中：</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;5&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 报错：TypeError: can only concatenate str (not &quot;int&quot;) to str</span></span></code></pre></div><p>Python 会直接抛出错误。它会告诉你：“嘿，你试图把一个字符串和一个整数相加，我不知道你想干什么，是想拼接还是想数学运算？请你明确告诉我！”</p><p>这就是强类型的核心：<strong>严谨</strong>。它不相信隐式的猜测，它要求程序员明确地表达意图。如果你想运算，你必须显式地转换：<code>int(&quot;5&quot;) + 2</code>。</p><hr><h4 id="语言分类学-四大象限的博弈" tabindex="-1">语言分类学：四大象限的博弈 <a class="header-anchor" href="#语言分类学-四大象限的博弈" aria-label="Permalink to &quot;语言分类学：四大象限的博弈&quot;">​</a></h4><p>为了让你更清晰地理解编程语言的版图，我们不能只看“强弱”，还要结合“动静”。这两个维度交叉，构成了编程语言的<strong>四大象限</strong>。</p><p>我们可以把编程语言想象成一个坐标系： * <strong>横轴（类型检查时机）</strong>：左边是<strong>静态</strong>（编译时检查），右边是<strong>动态</strong>（运行时检查）。 * <strong>纵轴（类型转换严格度）</strong>：下边是<strong>强类型</strong>（严禁隐式转换），上边是<strong>弱类型</strong>（允许隐式转换）。</p><p>让我们看看 Python 和其他语言分别坐在哪个位置：</p><p><strong>静态强类型：严谨的“学院派”</strong> * <strong>代表语言</strong>：Java, C#, Go, Rust * <strong>特点</strong>：这是企业级开发的最爱。它们要求你在使用变量前必须声明类型（静态），并且严禁乱搞类型转换（强类型）。 * <strong>体验</strong>：写代码时虽然繁琐（要写很多类型定义），但编译器会帮你挡掉绝大多数错误。代码运行效率高，维护起来非常安心。</p><p><strong>动态强类型：灵活的“实干派”</strong> * <strong>代表语言</strong>：<strong>Python</strong>, Ruby * <strong>特点</strong>：这就是 Python 的舒适区。它们不需要你声明类型（动态），写起来飞快；但在运算时又很讲原则（强类型），绝不偷偷帮你转换类型。 * <strong>体验</strong>：开发效率极高，代码简洁。虽然类型错误只能在运行时发现，但因为禁止了隐式转换，逻辑上的 Bug 反而比弱类型语言少得多。</p><p><strong>静态弱类型：自由的“底层派”</strong> * <strong>代表语言</strong>：C, C++ * <strong>特点</strong>：这是系统编程的基石。类型在编译时确定（静态），但为了性能和灵活性，它们允许很多隐式转换（弱类型）。比如在 C 语言中，你可以把字符 &#39;A&#39; 直接当作整数 65 来运算。 * <strong>体验</strong>：赋予程序员极大的权力，可以直接操作内存。但“能力越大，责任越大”，如果你不小心，这些隐式转换和指针操作可能会引发难以察觉的崩溃。</p><p><strong>动态弱类型：随性的“脚本派”</strong> * <strong>代表语言</strong>：JavaScript, PHP, Perl * <strong>特点</strong>：这是 Web 开发的早期功臣。类型随值变（动态），而且为了让你少写代码，它会疯狂地帮你做类型转换（弱类型）。 * <strong>体验</strong>：上手极快，代码极其灵活。但在大型项目中，<code>&quot;5&quot; + 2</code> 到底等于 <code>&quot;52&quot;</code> 还是 <code>7</code>，可能会成为团队争吵的源头。这也是为什么现代 JavaScript 开发越来越推崇 TypeScript（一种静态强类型的 JS 超集）的原因。</p><p><strong>相关链接：</strong>（这里是我看到的有关这部分比较好的文章）</p><p><a href="https://cloud.tencent.com/developer/article/2499767" target="_blank" rel="noreferrer">【Python 入门基础】—— 人工智能“超级引擎”，AI界的“瑞士军刀”</a></p>`,102)])])}const y=o(r,[["render",e]]);export{g as __pageData,y as default};
